import { test, expect } from "@playwright/test";

test.describe("Chat Interface", () => {
  test.beforeEach(async ({ page }) => {
    await page.goto("/");
  });

  test("should display the application header", async ({ page }) => {
    const header = page.locator("h1");
    await expect(header).toContainText("Belt Terminal");
  });

  test("should show connection status indicator", async ({ page }) => {
    const connectionStatus = page.getByText(/Connected|Disconnected/);
    await expect(connectionStatus).toBeVisible();
  });

  test("should display session selector", async ({ page }) => {
    const sessionLabel = page.getByText("Session:");
    await expect(sessionLabel).toBeVisible();
  });

  test("should show new session button", async ({ page }) => {
    const newButton = page.getByRole("button", { name: "New" });
    await expect(newButton).toBeVisible();
  });

  test("should open session creation form when clicking New", async ({ page }) => {
    const newButton = page.getByRole("button", { name: "New" });
    await newButton.click();

    const sessionNameInput = page.getByPlaceholder("Session name");
    await expect(sessionNameInput).toBeVisible();

    const workingDirInput = page.getByPlaceholder(/Working directory/);
    await expect(workingDirInput).toBeVisible();

    const createButton = page.getByRole("button", { name: "Create" });
    await expect(createButton).toBeVisible();
  });

  test("should cancel session creation", async ({ page }) => {
    const newButton = page.getByRole("button", { name: "New" });
    await newButton.click();

    const cancelButton = page.getByRole("button", { name: "Cancel" });
    await cancelButton.click();

    const sessionNameInput = page.getByPlaceholder("Session name");
    await expect(sessionNameInput).not.toBeVisible();
  });

  test("should display no session selected message initially", async ({ page }) => {
    const noSessionMessage = page.getByText("No session selected");
    await expect(noSessionMessage).toBeVisible();
  });
});

test.describe("Session Management", () => {
  test("should create a new session", async ({ page }) => {
    await page.goto("/");

    // Open session creation form
    await page.getByRole("button", { name: "New" }).click();

    // Fill in session details
    await page.getByPlaceholder("Session name").fill("Test Session");
    await page.getByPlaceholder(/Working directory/).fill("/tmp/test");

    // Create the session
    await page.getByRole("button", { name: "Create" }).click();

    // Wait for session to be created and selected
    await expect(page.getByText("Test Session")).toBeVisible({ timeout: 5000 });
  });

  test("should display reminders panel after session creation", async ({ page }) => {
    await page.goto("/");

    // Create a session first
    await page.getByRole("button", { name: "New" }).click();
    await page.getByPlaceholder("Session name").fill("Reminder Test");
    await page.getByRole("button", { name: "Create" }).click();

    // Check reminders panel is visible
    const remindersButton = page.getByRole("button", { name: /Reminders/ });
    await expect(remindersButton).toBeVisible({ timeout: 5000 });
  });
});

test.describe("Reminder Panel", () => {
  test.beforeEach(async ({ page }) => {
    await page.goto("/");

    // Create a session to access reminder panel
    await page.getByRole("button", { name: "New" }).click();
    await page.getByPlaceholder("Session name").fill("Reminder Test Session");
    await page.getByRole("button", { name: "Create" }).click();

    // Wait for session to load
    await expect(page.getByRole("button", { name: /Reminders/ })).toBeVisible({
      timeout: 5000,
    });
  });

  test("should expand reminder panel", async ({ page }) => {
    const remindersButton = page.getByRole("button", { name: /Reminders/ });
    await remindersButton.click();

    const addReminderInput = page.getByPlaceholder("Add a reminder...");
    await expect(addReminderInput).toBeVisible();
  });

  test("should have add reminder button", async ({ page }) => {
    await page.getByRole("button", { name: /Reminders/ }).click();

    const addButton = page.getByRole("button", { name: "Add" });
    await expect(addButton).toBeVisible();
  });

  test("should have persistent checkbox", async ({ page }) => {
    await page.getByRole("button", { name: /Reminders/ }).click();

    const persistentLabel = page.getByText("Persistent");
    await expect(persistentLabel).toBeVisible();
  });

  test("should have priority input", async ({ page }) => {
    await page.getByRole("button", { name: /Reminders/ }).click();

    const priorityLabel = page.getByText("Priority:");
    await expect(priorityLabel).toBeVisible();
  });

  test("should add a new reminder", async ({ page }) => {
    await page.getByRole("button", { name: /Reminders/ }).click();

    // Fill in reminder
    const reminderInput = page.getByPlaceholder("Add a reminder...");
    await reminderInput.fill("Remember to test");

    // Add the reminder
    await page.getByRole("button", { name: "Add" }).click();

    // Check reminder appears
    await expect(page.getByText("Remember to test")).toBeVisible({ timeout: 5000 });
  });
});

test.describe("Message Input", () => {
  test.beforeEach(async ({ page }) => {
    await page.goto("/");

    // Create a session
    await page.getByRole("button", { name: "New" }).click();
    await page.getByPlaceholder("Session name").fill("Message Test");
    await page.getByRole("button", { name: "Create" }).click();

    // Wait for interface to load
    await expect(page.getByRole("button", { name: /Reminders/ })).toBeVisible({
      timeout: 5000,
    });
  });

  test("should display message input", async ({ page }) => {
    const messageInput = page.getByPlaceholder(/Type a message/);
    await expect(messageInput).toBeVisible();
  });

  test("should display send button", async ({ page }) => {
    const sendButton = page.getByRole("button", { name: "Send" });
    await expect(sendButton).toBeVisible();
  });

  test("should disable send button when input is empty", async ({ page }) => {
    const sendButton = page.getByRole("button", { name: "Send" });
    await expect(sendButton).toBeDisabled();
  });

  test("should enable send button when input has text", async ({ page }) => {
    const messageInput = page.getByPlaceholder(/Type a message/);
    await messageInput.fill("Hello Claude");

    const sendButton = page.getByRole("button", { name: "Send" });
    await expect(sendButton).toBeEnabled();
  });
});

test.describe("No Messages State", () => {
  test.beforeEach(async ({ page }) => {
    await page.goto("/");

    // Create a new session
    await page.getByRole("button", { name: "New" }).click();
    await page.getByPlaceholder("Session name").fill("Empty Session");
    await page.getByRole("button", { name: "Create" }).click();

    await expect(page.getByRole("button", { name: /Reminders/ })).toBeVisible({
      timeout: 5000,
    });
  });

  test("should show no messages state", async ({ page }) => {
    const noMessagesText = page.getByText("No messages yet");
    await expect(noMessagesText).toBeVisible();
  });

  test("should show start conversation hint", async ({ page }) => {
    const hintText = page.getByText(/Start a conversation/);
    await expect(hintText).toBeVisible();
  });
});

