    44→
    45→export function handleWebSocketOpen(ws: WS) {
    46→  const id = crypto.randomUUID();
    47→  ws.data = { id, connectedAt: Date.now() };
    48→  clients.set(id, ws);
    49→  console.log(`[WS] Client connected: ${id}`);
    50→}
    51→
    52→export function handleWebSocketClose(ws: WS) {
    53→  if (ws.data?.id) {
    54→    clients.delete(ws.data.id);
    55→    console.log(`[WS] Client disconnected: ${ws.data.id}`);
    56→  }
    57→}
    58→
    59→export async function handleWebSocketMessage(ws: WS, rawMessage: string | Buffer) {
    60→  const messageStr = typeof rawMessage === "string" ? rawMessage : rawMessage.toString();
    61→
    62→  let parsed: unknown;
    63→  try {
    64→    parsed = JSON.parse(messageStr);
    65→  } catch {
    66→    send(ws, { type: "stream_error", error: "Invalid JSON" });
    67→    return;
    68→  }
    69→
    70→  const message = parsed as { type: string };
    71→
    72→  if (message.type === "ping") {
    73→    ws.send(JSON.stringify({ type: "pong" }));
    74→    return;
    75→  }
    76→
    77→  if (message.type === "send_message") {
    78→    await handleSendMessage(ws, parsed as SendMessageRequest);
    79→  }
    80→}
    81→
    82→async function handleSendMessage(ws: WS, request: SendMessageRequest) {
    83→  const {
    84→    claudeSessionId,
    85→    workingDirectory,
    86→    content,
    87→    reminderContents,
    88→    allowedTools,
    89→    messageId,
    90→  } = request;
    91→
    92→  // Build system prompt with reminders
    93→  const systemPrompt = reminderContents && reminderContents.length > 0
    94→    ? buildReminderSystemPrompt(
    95→        reminderContents.map((c) => ({ content: c, persistent: true }))
    96→      )
    97→    : undefined;
    98→
    99→  // Send stream start
   100→  send(ws, { type: "stream_start", messageId });
   101→
   102→  // Create Claude CLI controller
   103→  const controller = createClaudeController({
   104→    prompt: content,
   105→    workingDirectory,
   106→    sessionId: claudeSessionId,
   107→    systemPrompt,
   108→    allowedTools,
   109→  });
   110→
   111→  let fullText = "";
   112→  const toolCalls: string[] = [];
   113→  let resultEvent: ClaudeResultEvent | null = null;
   114→  let newSessionId: string | null = null;
   115→
   116→  controller.on("text", (chunk) => {
   117→    fullText += chunk;
   118→    send(ws, { type: "stream_chunk", messageId, content: chunk });
   119→  });
   120→
   121→  controller.on("tool_use", (tool) => {
   122→    toolCalls.push(tool);
   123→  });
   124→
   125→  controller.on("data", (event) => {
   126→    if ("session_id" in event && event.session_id) {
   127→      newSessionId = event.session_id as string;
   128→    }
   129→  });
   130→
   131→  controller.on("result", (result) => {
   132→    resultEvent = result;
   133→    if (result.session_id) {
   134→      newSessionId = result.session_id;
   135→    }
   136→  });
   137→
   138→  controller.on("error", (error) => {
   139→    console.error("[Claude] Error:", error);
   140→    send(ws, { type: "stream_error", messageId, error: error.message });
   141→  });
   142→
   143→  controller.on("end", () => {
   144→    send(ws, {
   145→      type: "stream_complete",
   146→      messageId,
   147→      content: fullText,
   148→      metadata: {
   149→        toolCalls: toolCalls.length > 0 ? toolCalls : undefined,
   150→        claudeSessionId: newSessionId ?? undefined,
   151→        cost: resultEvent?.cost_usd,
   152→        duration: resultEvent?.duration_ms,
   153→      },
   154→    });
   155→  });
   156→}
   157→
   158→export function getConnectedClients(): number {
   159→  return clients.size;
   160→}
   161→

