import { spawn, type ChildProcess } from "child_process";
import { createInterface, type Interface } from "readline";
import { EventEmitter } from "events";

export interface ClaudeStreamEvent {
  type: string;
  [key: string]: unknown;
}

export interface ClaudeAssistantMessage {
  type: "assistant";
  message: {
    id: string;
    type: "message";
    role: "assistant";
    content: Array<{
      type: "text" | "tool_use" | "tool_result";
      text?: string;
      id?: string;
      name?: string;
      input?: Record<string, unknown>;
    }>;
    model: string;
    stop_reason: string | null;
    stop_sequence: string | null;
    usage: {
      input_tokens: number;
      output_tokens: number;
    };
  };
  session_id: string;
}

export interface ClaudeResultEvent {
  type: "result";
  subtype: string;
  cost_usd: number;
  duration_ms: number;
  duration_api_ms: number;
  is_error: boolean;
  num_turns: number;
  result: string;
  session_id: string;
  total_cost_usd: number;
}

export interface ClaudeSystemEvent {
  type: "system";
  subtype: string;
  message?: string;
  [key: string]: unknown;
}

export type ClaudeEvent = ClaudeAssistantMessage | ClaudeResultEvent | ClaudeSystemEvent | ClaudeStreamEvent;

export interface ClaudeOptions {
  prompt: string;
  workingDirectory: string;
  sessionId?: string;
  systemPrompt?: string;
  allowedTools?: string[];
  maxTurns?: number;
}

export interface ClaudeController extends EventEmitter {
  on(event: "data", listener: (data: ClaudeEvent) => void): this;
  on(event: "text", listener: (text: string) => void): this;
  on(event: "tool_use", listener: (tool: string, input: Record<string, unknown>) => void): this;
  on(event: "result", listener: (result: ClaudeResultEvent) => void): this;
  on(event: "error", listener: (error: Error) => void): this;
  on(event: "end", listener: () => void): this;
  emit(event: "data", data: ClaudeEvent): boolean;
  emit(event: "text", text: string): boolean;
  emit(event: "tool_use", tool: string, input: Record<string, unknown>): boolean;
  emit(event: "result", result: ClaudeResultEvent): boolean;
  emit(event: "error", error: Error): boolean;
  emit(event: "end"): boolean;
}

export function createClaudeController(options: ClaudeOptions): ClaudeController {
  const emitter = new EventEmitter() as ClaudeController;
  let childProcess: ChildProcess | null = null;
  let readline: Interface | null = null;

  const args: string[] = ["-p", options.prompt, "--output-format", "stream-json"];

  if (options.sessionId) {
    args.push("--resume", options.sessionId);
  }

  if (options.systemPrompt) {
    args.push("--append-system-prompt", options.systemPrompt);
  }

  if (options.allowedTools && options.allowedTools.length > 0) {
    args.push("--allowedTools", options.allowedTools.join(","));
  }

  if (options.maxTurns) {
    args.push("--max-turns", String(options.maxTurns));
  }

  setImmediate(() => {
    try {
      childProcess = spawn("claude", args, {
        cwd: options.workingDirectory,
        stdio: ["pipe", "pipe", "pipe"],
        env: { ...process.env, FORCE_COLOR: "0" },
      });

      readline = createInterface({
        input: childProcess.stdout!,
        crlfDelay: Infinity,
      });

      let accumulatedText = "";

      readline.on("line", (line: string) => {
        if (!line.trim()) return;

        try {
          const event = JSON.parse(line) as ClaudeEvent;
          emitter.emit("data", event);

          if (event.type === "assistant") {
            const assistantEvent = event as ClaudeAssistantMessage;
            for (const block of assistantEvent.message.content) {
              if (block.type === "text" && block.text) {
                accumulatedText += block.text;
                emitter.emit("text", block.text);
              } else if (block.type === "tool_use" && block.name) {
                emitter.emit("tool_use", block.name, block.input ?? {});
              }
            }
          } else if (event.type === "result") {
            emitter.emit("result", event as ClaudeResultEvent);
          }
        } catch {
          // Ignore non-JSON lines (e.g., progress indicators)
        }
      });

      childProcess.stderr?.on("data", (data: Buffer) => {
        const text = data.toString();
        if (text.includes("Error") || text.includes("error")) {
          emitter.emit("error", new Error(text));
        }
      });

      childProcess.on("close", (code: number | null) => {
        readline?.close();
        if (code !== 0 && code !== null) {
          emitter.emit("error", new Error(`Claude process exited with code ${code}`));
        }
        emitter.emit("end");
      });

      childProcess.on("error", (err: Error) => {
        emitter.emit("error", err);
        emitter.emit("end");
      });
    } catch (err) {
      emitter.emit("error", err instanceof Error ? err : new Error(String(err)));
      emitter.emit("end");
    }
  });

  return emitter;
}

export async function runClaude(options: ClaudeOptions): Promise<{
  text: string;
  sessionId: string | null;
  result: ClaudeResultEvent | null;
  toolCalls: Array<{ tool: string; input: Record<string, unknown> }>;
}> {
  return new Promise((resolve, reject) => {
    const controller = createClaudeController(options);

    let text = "";
    let sessionId: string | null = null;
    let result: ClaudeResultEvent | null = null;
    const toolCalls: Array<{ tool: string; input: Record<string, unknown> }> = [];

    controller.on("text", (chunk) => {
      text += chunk;
    });

    controller.on("tool_use", (tool, input) => {
      toolCalls.push({ tool, input });
    });

    controller.on("data", (event) => {
      if ("session_id" in event && event.session_id) {
        sessionId = event.session_id as string;
      }
    });

    controller.on("result", (r) => {
      result = r;
      if (r.session_id) {
        sessionId = r.session_id;
      }
    });

    controller.on("error", reject);

    controller.on("end", () => {
      resolve({ text, sessionId, result, toolCalls });
    });
  });
}

export function buildReminderSystemPrompt(reminders: Array<{ content: string; persistent: boolean }>): string {
  if (reminders.length === 0) return "";

  const lines = reminders.map((r) => {
    const prefix = r.persistent ? "[PERSISTENT]" : "[ONE-TIME]";
    return `- ${prefix} ${r.content}`;
  });

  return `ACTIVE REMINDERS (follow these instructions):
${lines.join("\n")}`;
}

