     1→import { useState, useEffect, useCallback, useRef } from "react";
     2→import { useQuery, useMutation } from "convex/react";
     3→import { api } from "../../convex/_generated/api";
     4→import type { SessionId, MessageId, Session, Message, Reminder, MessageMetadata } from "../lib/types";
     5→
     6→const WS_URL = import.meta.env.PUBLIC_WS_URL || "ws://localhost:3001/ws";
     7→
     8→interface StreamingState {
     9→  messageId: string | null;
    10→  content: string;
    11→}
    12→
    13→interface ClaudeStreamMessage {
    14→  type: "stream_start" | "stream_chunk" | "stream_complete" | "stream_error" | "pong";
    15→  messageId?: string;
    16→  content?: string;
    17→  metadata?: {
    18→    toolCalls?: string[];
    19→    claudeSessionId?: string;
    20→    cost?: number;
    21→    duration?: number;
    22→  };
    23→  error?: string;
    24→}
    25→
    26→export interface UseChatState {
    27→  sessions: Session[] | undefined;
    28→  currentSession: Session | null | undefined;
    29→  messages: Message[] | undefined;
    30→  reminders: Reminder[] | undefined;
    31→  isConnected: boolean;
    32→  isLoading: boolean;
    33→  streamingMessageId: string | null;
    34→  streamingContent: string;
    35→  error: string | null;
    36→}
    37→
    38→export interface UseChatActions {
    39→  createSession: (name: string, cwd: string) => Promise<SessionId>;
    40→  selectSession: (sessionId: SessionId) => void;
    41→  archiveSession: (sessionId: SessionId) => Promise<void>;
    42→  deleteSession: (sessionId: SessionId) => Promise<void>;
    43→  sendMessage: (content: string, allowedTools?: string[]) => void;
    44→  addReminder: (content: string, persistent: boolean, priority?: number) => Promise<void>;
    45→  toggleReminder: (id: Reminder["_id"], active: boolean) => Promise<void>;
    46→  deleteReminder: (id: Reminder["_id"]) => Promise<void>;
    47→}
    48→
    49→export type UseChat = UseChatState & UseChatActions;
    50→
    51→export interface UseChatOptions {
    52→  sessionId?: SessionId | null;
    53→}
    54→
    55→export function useChat(options: UseChatOptions = {}): UseChat {
    56→  const [selectedSessionId, setSelectedSessionId] = useState<SessionId | null>(
    57→    options.sessionId ?? null
    58→  );
    59→  const [isConnected, setIsConnected] = useState(false);
    60→  const [isLoading, setIsLoading] = useState(false);
    61→  const [streaming, setStreaming] = useState<StreamingState>({
    62→    messageId: null,
    63→    content: "",
    64→  });
    65→  const [error, setError] = useState<string | null>(null);
    66→
    67→  const wsRef = useRef<WebSocket | null>(null);
    68→  const reconnectTimeoutRef = useRef<ReturnType<typeof setTimeout> | undefined>(undefined);
    69→
    70→  // Convex queries
    71→  const sessions = useQuery(api.sessions.list, { status: "active" });
    72→  const currentSession = useQuery(
    73→    api.sessions.get,
    74→    selectedSessionId ? { id: selectedSessionId } : "skip"
    75→  );
    76→  const messages = useQuery(
    77→    api.messages.list,
    78→    selectedSessionId ? { sessionId: selectedSessionId } : "skip"
    79→  );
    80→  const reminders = useQuery(
    81→    api.reminders.list,
    82→    selectedSessionId ? { sessionId: selectedSessionId } : {}
    83→  );
    84→
    85→  // Convex mutations
    86→  const createSessionMutation = useMutation(api.sessions.create);
    87→  const archiveSessionMutation = useMutation(api.sessions.archive);
    88→  const deleteSessionMutation = useMutation(api.sessions.remove);
    89→  const createMessageMutation = useMutation(api.messages.create);
    90→  const updateMessageContentMutation = useMutation(api.messages.updateContent);
    91→  const updateMessageMetadataMutation = useMutation(api.messages.updateMetadata);
    92→  const updateClaudeSessionIdMutation = useMutation(api.sessions.updateClaudeSessionId);
    93→  const createReminderMutation = useMutation(api.reminders.create);
    94→  const toggleReminderMutation = useMutation(api.reminders.toggle);
    95→  const deleteReminderMutation = useMutation(api.reminders.remove);
    96→  const deactivateNonPersistentMutation = useMutation(api.reminders.deactivateNonPersistent);
    97→
    98→  // Track pending message updates
    99→  const pendingUpdatesRef = useRef<Map<string, {
   100→    messageId: MessageId;
   101→    sessionId: SessionId;
   102→  }>>(new Map());
   103→
   104→  // WebSocket message handler
   105→  const handleWsMessage = useCallback(async (event: MessageEvent) => {
   106→    try {
   107→      const message = JSON.parse(event.data) as ClaudeStreamMessage;
   108→
   109→      switch (message.type) {
   110→        case "stream_start":
   111→          setIsLoading(true);
   112→          setStreaming({ messageId: message.messageId ?? null, content: "" });
   113→          break;
   114→
   115→        case "stream_chunk":
   116→          if (message.content) {
   117→            setStreaming((prev) => ({
   118→              ...prev,
   119→              content: prev.content + message.content,
   120→            }));
   121→          }
   122→          break;
   123→
   124→        case "stream_complete": {
   125→          setIsLoading(false);
   126→          setStreaming({ messageId: null, content: "" });
   127→
   128→          // Update message content in Convex
   129→          if (message.messageId && message.content) {
   130→            const pending = pendingUpdatesRef.current.get(message.messageId);
   131→            if (pending) {
   132→              await updateMessageContentMutation({
   133→                id: pending.messageId,
   134→                content: message.content,
   135→              });
   136→
   137→              if (message.metadata) {
   138→                await updateMessageMetadataMutation({
   139→                  id: pending.messageId,
   140→                  metadata: {
   141→                    toolCalls: message.metadata.toolCalls,
   142→                    claudeSessionId: message.metadata.claudeSessionId,
   143→                    cost: message.metadata.cost,
   144→                    duration: message.metadata.duration,
   145→                  },
   146→                });
   147→
   148→                // Update Claude session ID if new
   149→                if (message.metadata.claudeSessionId) {
   150→                  await updateClaudeSessionIdMutation({
   151→                    id: pending.sessionId,
   152→                    claudeSessionId: message.metadata.claudeSessionId,
   153→                  });
