    20→
    21→      return [...globalReminders, ...sessionReminders].sort(
    22→        (a, b) => b.priority - a.priority
    23→      );
    24→    }
    25→
    26→    return await ctx.db.query("reminders").collect();
    27→  },
    28→});
    29→
    30→export const getActive = query({
    31→  args: {
    32→    sessionId: v.optional(v.id("sessions")),
    33→  },
    34→  handler: async (ctx, args) => {
