import { describe, it, expect } from "vitest";
import {
  injectReminders,
  filterTriggeredReminders,
  createDefaultReminders,
} from "../../src/lib/injector";
import type {
  Reminder,
  Message,
  Session,
  MessageMetadata,
  SessionId,
  MessageId,
  ReminderId,
} from "../../src/lib/types";

const createMockReminder = (
  overrides: Partial<Omit<Reminder, "_id" | "_creationTime">> & {
    _id?: string;
    _creationTime?: number;
  } = {},
): Reminder => ({
  _id: (overrides._id ?? `reminder-${Math.random().toString(36).slice(2)}`) as ReminderId,
  _creationTime: overrides._creationTime ?? Date.now(),
  sessionId: overrides.sessionId,
  content: overrides.content ?? "Test reminder",
  persistent: overrides.persistent ?? false,
  active: overrides.active ?? true,
  priority: overrides.priority ?? 0,
  triggerCondition: overrides.triggerCondition,
});

const createMockSession = (
  overrides: Partial<Omit<Session, "_id" | "_creationTime">> & {
    _id?: string;
    _creationTime?: number;
  } = {},
): Session => ({
  _id: (overrides._id ?? `session-${Math.random().toString(36).slice(2)}`) as SessionId,
  _creationTime: overrides._creationTime ?? Date.now(),
  name: overrides.name ?? "Test Session",
  workingDirectory: overrides.workingDirectory ?? "/test/project",
  claudeSessionId: overrides.claudeSessionId,
  lastActiveAt: overrides.lastActiveAt ?? Date.now(),
  status: overrides.status ?? "active",
});

const createMockMessage = (
  overrides: Partial<Omit<Message, "_id" | "_creationTime">> & {
    _id?: string;
    _creationTime?: number;
  } = {},
  metadata?: MessageMetadata,
): Message => ({
  _id: (overrides._id ?? `msg-${Math.random().toString(36).slice(2)}`) as MessageId,
  _creationTime: overrides._creationTime ?? Date.now(),
  sessionId: (overrides.sessionId ?? "session-123") as SessionId,
  role: overrides.role ?? "user",
  content: overrides.content ?? "Test message",
  metadata: metadata ?? overrides.metadata,
});

describe("Chat Flow Integration", () => {
  describe("Message Injection Flow", () => {
    it("should inject reminders into user message before sending", () => {
      const userMessage = "Please implement the login feature";
      const reminders = [
        createMockReminder({
          content: "Remember to write tests",
          priority: 10,
          persistent: true,
        }),
        createMockReminder({
          content: "Commit incrementally",
          priority: 5,
          persistent: true,
        }),
      ];

      const result = injectReminders(userMessage, reminders);

      expect(result.hasReminders).toBe(true);
      expect(result.injectedReminders).toHaveLength(2);
      expect(result.enhancedContent).toContain("<system-reminder>");
      expect(result.enhancedContent).toContain("Remember to write tests");
      expect(result.enhancedContent).toContain("Commit incrementally");
      expect(result.enhancedContent).toContain(userMessage);
    });

    it("should filter reminders by trigger condition", () => {
      const reminders = [
        createMockReminder({
          content: "Commit reminder",
          triggerCondition: "implement,create,add",
          active: true,
        }),
        createMockReminder({
          content: "Test reminder",
          triggerCondition: "fix,bug",
          active: true,
        }),
        createMockReminder({
          content: "General reminder",
          active: true,
        }),
      ];

      const implementMessage = "Implement user authentication";
      const fixMessage = "Fix the login bug";
      const readMessage = "Read the configuration file";

      const implementFiltered = filterTriggeredReminders(reminders, implementMessage);
      expect(implementFiltered).toHaveLength(2);
      expect(implementFiltered.map((r) => r.content)).toContain("Commit reminder");
      expect(implementFiltered.map((r) => r.content)).toContain("General reminder");

      const fixFiltered = filterTriggeredReminders(reminders, fixMessage);
      expect(fixFiltered).toHaveLength(2);
      expect(fixFiltered.map((r) => r.content)).toContain("Test reminder");
      expect(fixFiltered.map((r) => r.content)).toContain("General reminder");

      const readFiltered = filterTriggeredReminders(reminders, readMessage);
      expect(readFiltered).toHaveLength(1);
      expect(readFiltered[0].content).toBe("General reminder");
    });

    it("should handle one-time vs persistent reminders", () => {
      const oneTimeReminder = createMockReminder({
        content: "One-time task",
        persistent: false,
        active: true,
      });

      const persistentReminder = createMockReminder({
        content: "Always remember",
        persistent: true,
        active: true,
      });

      const result = injectReminders("Test", [oneTimeReminder, persistentReminder]);

      expect(result.enhancedContent).toContain("[ONE-TIME]");
      expect(result.enhancedContent).toContain("[PERSISTENT]");
    });
  });

  describe("Session Lifecycle", () => {
    it("should create session with correct initial state", () => {
      const now = Date.now();
      const session = createMockSession({
        name: "Development Session",
        workingDirectory: "/home/user/project",
        _creationTime: now,
        lastActiveAt: now,
      });

      expect(session.status).toBe("active");
      expect(session.name).toBe("Development Session");
      expect(session.workingDirectory).toBe("/home/user/project");
      expect(session.lastActiveAt).toBe(session._creationTime);
    });

    it("should track session with Claude session ID", () => {
      const session = createMockSession({
        claudeSessionId: "claude-abc-123",
      });

      expect(session.claudeSessionId).toBe("claude-abc-123");
    });
  });

  describe("Message History", () => {
    it("should maintain conversation order", () => {
      const messages: Message[] = [
        createMockMessage({
          role: "user",
          content: "Hello",
          _creationTime: 1000,
        }),
        createMockMessage({
          role: "assistant",
          content: "Hi! How can I help?",
          _creationTime: 2000,
        }),
        createMockMessage({
          role: "user",
          content: "Fix the bug",
          _creationTime: 3000,
        }),
        createMockMessage(
          {
            role: "assistant",
            content: "I'll fix it now.",
            _creationTime: 4000,
          },
          { toolCalls: ["Read", "Edit"] },
        ),
      ];

      const sorted = [...messages].sort((a, b) => a._creationTime - b._creationTime);
      expect(sorted[0].role).toBe("user");
      expect(sorted[1].role).toBe("assistant");
      expect(sorted[2].role).toBe("user");
      expect(sorted[3].role).toBe("assistant");

      expect(sorted[3].metadata?.toolCalls).toContain("Edit");
    });

    it("should track injected reminders in message metadata", () => {
      const message = createMockMessage(
        {
          role: "user",
          content: "Implement feature",
        },
        {
          injectedReminders: [
            "Remember to commit",
            "Write tests",
          ],
        },
      );

      expect(message.metadata?.injectedReminders).toHaveLength(2);
      expect(message.metadata?.injectedReminders).toContain("Remember to commit");
    });
  });

  describe("Default Reminders Setup", () => {
    it("should create useful default reminders for development", () => {
      const defaults = createDefaultReminders("session-123");

      expect(defaults.length).toBeGreaterThan(0);

      const hasCommitReminder = defaults.some((r) =>
        r.content.toLowerCase().includes("commit"),
      );
      expect(hasCommitReminder).toBe(true);

      const hasTestReminder = defaults.some((r) =>
        r.content.toLowerCase().includes("test"),
      );
      expect(hasTestReminder).toBe(true);
    });

    it("should set appropriate trigger conditions", () => {
      const defaults = createDefaultReminders();

      const commitReminder = defaults.find((r) =>
        r.content.toLowerCase().includes("commit"),
      );

      if (commitReminder?.triggerCondition) {
        expect(commitReminder.triggerCondition).toContain("implement");
      }
    });
  });

  describe("Full Conversation Simulation", () => {
    it("should simulate a complete conversation flow", () => {
      const session = createMockSession({
        name: "Feature Implementation",
        workingDirectory: "/app",
      });

      const reminders = [
        createMockReminder({
          content: "Commit changes after each feature",
          priority: 10,
          persistent: true,
        }),
        createMockReminder({
          content: "Run tests before committing",
          priority: 8,
          persistent: true,
        }),
      ];

      const userPrompt = "Implement the user login feature";

      const injectionResult = injectReminders(userPrompt, reminders);
      expect(injectionResult.hasReminders).toBe(true);

      const userMessage = createMockMessage(
        {
          sessionId: session._id,
          role: "user",
          content: userPrompt,
        },
        {
          injectedReminders: injectionResult.injectedReminders,
        },
      );

      expect(userMessage.metadata?.injectedReminders).toHaveLength(2);

      const assistantMessage = createMockMessage(
        {
          sessionId: session._id,
          role: "assistant",
          content: "I'll implement the login feature. Let me start by reading the existing code.",
        },
        {
          toolCalls: ["Read", "Glob"],
        },
      );

      expect(assistantMessage.metadata?.toolCalls).toContain("Read");

      const followUpPrompt = "Now add the password validation";
      const followUpInjection = injectReminders(followUpPrompt, reminders);
      expect(followUpInjection.hasReminders).toBe(true);
    });
  });

  describe("Error Handling", () => {
    it("should handle empty reminder list gracefully", () => {
      const result = injectReminders("Test message", []);
      expect(result.enhancedContent).toBe("Test message");
      expect(result.hasReminders).toBe(false);
    });

    it("should handle all inactive reminders", () => {
      const reminders = [
        createMockReminder({ active: false }),
        createMockReminder({ active: false }),
      ];

      const result = injectReminders("Test", reminders);
      expect(result.hasReminders).toBe(false);
      expect(result.enhancedContent).toBe("Test");
    });

    it("should handle invalid regex in trigger condition", () => {
      const reminder = createMockReminder({
        triggerCondition: "[invalid regex",
        active: true,
      });

      const shouldTrigger = filterTriggeredReminders(
        [reminder],
        "[invalid regex test",
      );

      expect(shouldTrigger.length).toBe(1);
    });
  });
});

