import type { Reminder } from "./types";

export interface InjectionResult {
  enhancedContent: string;
  injectedReminders: string[];
  hasReminders: boolean;
}

export function formatReminder(reminder: Reminder): string {
  const prefix = reminder.persistent ? "[PERSISTENT]" : "[ONE-TIME]";
  const priority = reminder.priority > 0 ? ` (priority: ${reminder.priority})` : "";
  return `${prefix}${priority} ${reminder.content}`;
}

export function formatReminderBlock(reminders: Reminder[]): string {
  if (reminders.length === 0) return "";

  const sorted = [...reminders].sort((a, b) => b.priority - a.priority);
  const formatted = sorted.map((r) => `- ${formatReminder(r)}`).join("\n");

  return `<system-reminder>
ACTIVE REMINDERS:
${formatted}
</system-reminder>`;
}

export function injectReminders(
  content: string,
  reminders: Reminder[],
): InjectionResult {
  const activeReminders = reminders.filter((r) => r.active);

  if (activeReminders.length === 0) {
    return {
      enhancedContent: content,
      injectedReminders: [],
      hasReminders: false,
    };
  }

  const reminderBlock = formatReminderBlock(activeReminders);
  const enhancedContent = `${reminderBlock}\n\n${content}`;

  return {
    enhancedContent,
    injectedReminders: activeReminders.map((r) => r.content),
    hasReminders: true,
  };
}

export function shouldTriggerReminder(
  reminder: Reminder,
  userMessage: string,
): boolean {
  if (!reminder.triggerCondition) return true;

  const condition = reminder.triggerCondition.trim();

  const looksLikeKeywords = /^[\w,\s-]+$/.test(condition) && condition.includes(",");

  if (looksLikeKeywords) {
    return condition
      .toLowerCase()
      .split(",")
      .some((keyword) =>
        userMessage.toLowerCase().includes(keyword.trim()),
      );
  }

  try {
    const pattern = new RegExp(condition, "i");
    return pattern.test(userMessage);
  } catch {
    return userMessage.toLowerCase().includes(condition.toLowerCase());
  }
}

export function filterTriggeredReminders(
  reminders: Reminder[],
  userMessage: string,
): Reminder[] {
  return reminders.filter(
    (r) => r.active && shouldTriggerReminder(r, userMessage),
  );
}

export interface ReminderTemplate {
  name: string;
  content: string;
  persistent: boolean;
  priority: number;
  triggerCondition?: string;
}

export const DEFAULT_REMINDER_TEMPLATES: ReminderTemplate[] = [
  {
    name: "Commit Reminder",
    content: "Remember to commit your changes incrementally with descriptive messages.",
    persistent: true,
    priority: 10,
    triggerCondition: "implement,add,create,fix,update,refactor",
  },
  {
    name: "Harness Progress",
    content: "Update the harness progress file after completing significant tasks.",
    persistent: true,
    priority: 8,
    triggerCondition: "complete,finish,done,implement",
  },
  {
    name: "Test Reminder",
    content: "Write tests for new functionality before marking the task complete.",
    persistent: true,
    priority: 9,
    triggerCondition: "implement,add,create,feature",
  },
  {
    name: "Type Safety",
    content: "Ensure all code is properly typed with TypeScript strict mode.",
    persistent: true,
    priority: 5,
  },
];

export interface CreateReminderInput {
  sessionId?: string;
  content: string;
  persistent: boolean;
  active: boolean;
  priority: number;
  triggerCondition?: string;
}

export function createDefaultReminders(
  sessionId?: string,
): CreateReminderInput[] {
  return DEFAULT_REMINDER_TEMPLATES.map((template) => ({
    sessionId: sessionId ?? undefined,
    content: template.content,
    persistent: template.persistent,
    active: true,
    priority: template.priority,
    triggerCondition: template.triggerCondition,
  }));
}
